import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F06_存貨與債務穩定度審計_財務分析專家.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F06_存貨與債務穩定度審計_財務分析專家.md"}'),l={name:"審計報告庫/財務審計/4967_十銓/20260428/F06_存貨與債務穩定度審計_財務分析專家.md"};function o(n,a,s,h,_,c){return e(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f06-存貨與債務穩定度審計-財務分析專家-審計報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務分析專家-審計報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨91.9億(+57.8%)AI備貨；短債30.5億(+311%)現金縮至7.1億。流動比1.43、速動比0.52，可控但槓桿升溫。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2025/12</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：存貨佔流動資產63.7%，週轉天數124.2天(改善25.5%)。負債比67.7%，長債僅0.6億全數集中短期。營業現金流-35.2億，現金從24.7億急縮至7.1億。</li><li><strong>診斷見解</strong>：存貨衝歷史新高但去化改善。成長靠外部融資，2026/1完成8億CB部分緩解壓力，但91.9億存貨遇價格反轉風險巨大。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-存貨變動與結構" tabindex="-1">1. 存貨變動與結構 <a class="header-anchor" href="#_1-存貨變動與結構" aria-label="Permalink to &quot;1. 存貨變動與結構&quot;">​</a></h3><ul><li><strong>核心重點</strong>：存貨33.6億→91.9億，Q4暴增109%。DRAM佔70%(DDR5 53.6%)。跌價損失Q1迴轉5億。</li><li><strong>深度見解</strong>：公司押注AI結構性缺貨擴大備貨，91.9億超出合理庫存(約34億)。跌價迴轉對毛利率有正面貢獻，但若價格反轉存貨成跌價敞口。</li></ul><h3 id="_2-償債壓力" tabindex="-1">2. 償債壓力 <a class="header-anchor" href="#_2-償債壓力" aria-label="Permalink to &quot;2. 償債壓力&quot;">​</a></h3><ul><li><strong>核心重點</strong>：流動比1.43，速動比0.52。現金覆蓋0.23倍(7.1/30.5億)，含應收後1.59倍。利息支用比0.23%。</li><li><strong>深度見解</strong>：速動比0.52扣除存貨僅覆蓋一半流動負債。利息負擔極輕，8億CB結構性改善短期資金壓力。</li></ul><h3 id="_3-債務結構" tabindex="-1">3. 債務結構 <a class="header-anchor" href="#_3-債務結構" aria-label="Permalink to &quot;3. 債務結構&quot;">​</a></h3><ul><li><strong>核心重點</strong>：總負債101.66億(+69.6%)，負債比67.7%。長債降至0.6億全數集中短期。營業現金流-35.2億。</li><li><strong>深度見解</strong>：債務極度短化，景氣上行效率高但反轉時30.5億短債展期壓力大。成長依賴外部融資，容錯空間小。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一</strong>：若DRAM跌20%，91.9億存貨面臨18.4億跌價(=淨利1.66倍)。2023年曾虧損，周期性風險不可忽視。公司跌價迴轉5億已反映在2025毛利率中，若價格反轉此紅利將迅速蒸發，毛利率可能回落至8-10%區間。</p></li><li><p><strong>空頭風險二</strong>：若營收降30%，7.1億現金難支撐。30.5億短債展期壓力大，8億CB僅覆蓋26%。追蹤2026Q1存貨週轉天數，回升140天以上為去化放緩訊號。建議關注銀行聯貸條件變動，若授信縮減將進一步壓縮營運彈性。</p></li><li><p><strong>空頭風險三</strong>：短債佔總負債99.4%，利率升0.5%年增利息1,525萬(佔淨利1.4%)。更關鍵的是景氣反轉時，30.5億短債集中到期的再融資風險。2024年營業現金流已為負，若2026Q1延續此趨勢，現金枯竭風險將急遽升高。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>：OK — TaiwanStockBalanceSheet/TaiwanStockFinancialStatements 4967，2023Q1-2025Q4完整。</li><li><strong>yfinance</strong>：OK — 4967.TW年度資產負債表及季度損益表完整。</li><li><strong>年報/法說</strong>：OK — 2025Q1法說會存貨組成；2025年報營收204.28億、淨利11.1億、EPS 13.06；2026/1 CB 8億。</li><li><strong>關鍵核對碼</strong>：存貨9,191,226,000；短債3,047,168,000；流動資產14,418,702,000/流動負債10,081,453,000；營業現金流-3,520,704,000。</li></ul>',19)])])}const g=t(l,[["render",o]]);export{u as __pageData,g as default};
